class Solution(object):
    def carPooling(self, trips, capacity):
        events = []
        for num_passengers, from_location, to_location in trips:
            events.append((from_location, num_passengers))
            events.append((to_location, -num_passengers))
        events.sort()
        current = 0
        for location, change in events:
            current += change
            if current > capacity:
                return False
        return True
